**Context:** El Via e-Jom project optimization - automatic WebP conversion for user uploads with batch optimization for existing images.

## Pattern: API Route for Image Optimization

Create `/app/api/optimize-image/route.ts` that:
1. Downloads image from Supabase Storage
2. Processes with sharp: resize to max-width 800px, convert to WebP, quality 80
3. Uploads optimized version back to Supabase
4. Returns URLs (original + optimized)

### Implementation

```typescript
// app/api/optimize-image/route.ts
import { createClient } from '@supabase/supabase-js'
import sharp from 'sharp'

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
)

export async function POST(request: Request) {
  const { imageUrl, bucket = 'products' } = await request.json()

  if (!imageUrl) {
    return Response.json({ error: 'imageUrl required' }, { status: 400 })
  }

  // 1. Download from Supabase
  const { data: downloadData } = await supabase.storage
    .from(bucket)
    .download(imageUrl.split('/').pop())

  if (!downloadData) {
    return Response.json({ error: 'Image not found' }, { status: 404 })
  }

  const buffer = Buffer.from(await downloadData.arrayBuffer())

  // 2. Process with sharp
  const optimized = await sharp(buffer)
    .resize({ width: 800, withoutEnlargement: true })  // Max 800px width
    .webp({ quality: 80 })  // WebP at 80% quality
    .toBuffer()

  // 3. Upload optimized version
  const filename = imageUrl.replace(/\.(jpg|jpeg|png)$/i, '.webp')
  const { error: uploadError } = await supabase.storage
    .from(bucket)
    .upload(filename, optimized, { contentType: 'image/webp' })

  if (uploadError) {
    return Response.json({ error: uploadError.message }, { status: 500 })
  }

  // 4. Return URLs
  return Response.json({
    original: imageUrl,
    optimized: filename,
  })
}
```

## Batch Optimization for Existing Images

Create `/app/api/batch-optimize-images/route.ts` for one-time optimization of all existing images.

```typescript
// app/api/batch-optimize-images/route.ts
import { createClient } from '@supabase/supabase-js'
import sharp from 'sharp'

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
)

export async function POST(request: Request) {
  // 1. Get all product images
  const { data: products } = await supabase
    .from('ej_products')
    .select('image_url')
    .not('image_url', 'is', null)

  if (!products) return Response.json({ processed: 0 })

  let processed = 0
  const results = []

  for (const product of products) {
    if (!product.image_url) continue

    // Skip already WebP
    if (product.image_url.endsWith('.webp')) {
      results.push({ url: product.image_url, status: 'already-WebP' })
      continue
    }

    // Download, optimize, upload (same as single route)
    const { data: downloadData } = await supabase.storage
      .from('products')
      .download(product.image_url.split('/').pop())

    if (!downloadData) {
      results.push({ url: product.image_url, status: 'not-found' })
      continue
    }

    const buffer = Buffer.from(await downloadData.arrayBuffer())
    const optimized = await sharp(buffer)
      .resize({ width: 800, withoutEnlargement: true })
      .webp({ quality: 80 })
      .toBuffer()

    const filename = product.image_url.replace(/\.(jpg|jpeg|png)$/i, '.webp')
    const { error: uploadError } = await supabase.storage
      .from('products')
      .upload(filename, optimized, { contentType: 'image/webp' })

    if (uploadError) {
      results.push({ url: product.image_url, status: 'failed', error: uploadError.message })
      continue
    }

    // Update product record with WebP URL
    const { error: updateError } = await supabase
      .from('ej_products')
      .update({ image_url: filename })
      .eq('id', product.id)

    if (updateError) {
      results.push({ url: product.image_url, status: 'update-failed' })
    } else {
      processed++
      results.push({ url: product.image_url, status: 'ok', new_url: filename })
    }
  }

  return Response.json({ processed, total: products.length, results })
}
```

## Admin UI Integration

Update `components/admin/image-upload.tsx` to add auto-optimization toggle.

```tsx
// components/admin/image-upload.tsx
const [autoOptimize, setAutoOptimize] = useState(true)

async function handleUpload(file: File) {
  let imageUrl = await uploadToSupabase(file)

  if (autoOptimize && !imageUrl.endsWith('.webp')) {
    // Call optimization API
    const res = await fetch('/api/optimize-image', {
      method: 'POST',
      body: JSON.stringify({ imageUrl, bucket: 'products' }),
    })
    const { optimized } = await res.json()
    imageUrl = optimized  // Use WebP version
  }

  onUpload(imageUrl)
}

return (
  <div>
    <input type="checkbox" checked={autoOptimize} onChange={e => setAutoOptimize(e.target.checked)} />
    <label>Auto-optimizar a WebP (800px, 80%)</label>
    {/* upload button */}
  </div>
)
```

## Batch Execution

Trigger batch optimization via admin or direct API call:

```bash
# From admin panel button or curl
curl -X POST https://tiendaelviajero.com.py/api/batch-optimize-images \
  -H "Content-Type: application/json" \
  -d '{}'
```

